  "inlineSchema": "// Prisma schema for the Tenant Service\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── Tenants ───\nmodel Tenant {\n  id        String       @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  name      String\n  slug      String       @unique\n  status    TenantStatus @default(TRIAL)\n  createdAt DateTime     @default(now()) @map(\"created_at\")\n  updatedAt DateTime     @updatedAt @map(\"updated_at\")\n\n  // Relations\n  settings     TenantSettings?\n  subscription Subscription?\n  members      TenantMember[]\n  invitations  Invitation[]\n  plans        Plan?           @relation(fields: [planId], references: [id])\n  planId       String?         @map(\"plan_id\") @db.Uuid\n\n  @@map(\"tenants\")\n}\n\nenum TenantStatus {\n  ACTIVE\n  TRIAL\n  SUSPENDED\n  CANCELLED\n}\n\n// ─── Tenant Settings ───\nmodel TenantSettings {\n  id       String @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  tenantId String @unique @map(\"tenant_id\") @db.Uuid\n  tenant   Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  // Branding\n  logoUrl        String? @map(\"logo_url\")\n  primaryColor   String  @default(\"#6366f1\") @map(\"primary_color\")\n  widgetPosition String  @default(\"bottom-right\") @map(\"widget_position\")\n  welcomeMessage String  @default(\"Hi! How can we help you today?\") @map(\"welcome_message\")\n  offlineMessage String  @default(\"We're currently offline. Leave a message and we'll get back to you.\") @map(\"offline_message\")\n\n  // AI Configuration\n  aiEnabled             Boolean @default(true) @map(\"ai_enabled\")\n  aiTone                String  @default(\"friendly\") @map(\"ai_tone\")\n  aiConfidenceThreshold Float   @default(0.7) @map(\"ai_confidence_threshold\")\n  aiMaxTokens           Int     @default(1024) @map(\"ai_max_tokens\")\n  aiSystemPrompt        String? @map(\"ai_system_prompt\")\n\n  // Widget\n  widgetEnabled      Boolean  @default(true) @map(\"widget_enabled\")\n  allowedDomains     String[] @default([]) @map(\"allowed_domains\")\n  preChatForm        Boolean  @default(true) @map(\"pre_chat_form\")\n  offlineFormEnabled Boolean  @default(true) @map(\"offline_form_enabled\")\n\n  // Notifications\n  emailOnNewConversation Boolean @default(true) @map(\"email_on_new_conversation\")\n  emailOnEscalation      Boolean @default(true) @map(\"email_on_escalation\")\n  pushEnabled            Boolean @default(true) @map(\"push_enabled\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  @@map(\"tenant_settings\")\n}\n\n// ─── Tenant Members ───\nmodel TenantMember {\n  id        String   @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  tenantId  String   @map(\"tenant_id\") @db.Uuid\n  tenant    Tenant   @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  userId    String   @map(\"user_id\") @db.Uuid\n  role      String   @default(\"AGENT\")\n  invitedBy String?  @map(\"invited_by\") @db.Uuid\n  joinedAt  DateTime @default(now()) @map(\"joined_at\")\n\n  @@unique([tenantId, userId])\n  @@index([tenantId])\n  @@map(\"tenant_members\")\n}\n\n// ─── Invitations ───\nmodel Invitation {\n  id        String           @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  tenantId  String           @map(\"tenant_id\") @db.Uuid\n  tenant    Tenant           @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  email     String\n  role      String           @default(\"AGENT\")\n  token     String           @unique\n  status    InvitationStatus @default(PENDING)\n  invitedBy String           @map(\"invited_by\") @db.Uuid\n  expiresAt DateTime         @map(\"expires_at\")\n  createdAt DateTime         @default(now()) @map(\"created_at\")\n\n  @@index([tenantId])\n  @@index([token])\n  @@map(\"invitations\")\n}\n\nenum InvitationStatus {\n  PENDING\n  ACCEPTED\n  EXPIRED\n  REVOKED\n}\n\n// ─── Plans ───\nmodel Plan {\n  id           String @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  name         String\n  tier         String @unique // starter, growth, business, enterprise\n  priceMonthly Int    @map(\"price_monthly\") // in cents\n  priceYearly  Int    @map(\"price_yearly\") // in cents\n\n  // Limits\n  aiMessagesPerMonth Int @map(\"ai_messages_per_month\")\n  contacts           Int\n  channels           Int\n  agents             Int\n  storageMb          Int @map(\"storage_mb\")\n\n  // Features\n  features  String[]\n  isActive  Boolean  @default(true) @map(\"is_active\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  tenants Tenant[]\n\n  @@map(\"plans\")\n}\n\n// ─── Subscriptions ───\nmodel Subscription {\n  id                   String             @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  tenantId             String             @unique @map(\"tenant_id\") @db.Uuid\n  tenant               Tenant             @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  stripeCustomerId     String?            @map(\"stripe_customer_id\")\n  stripeSubscriptionId String?            @map(\"stripe_subscription_id\")\n  status               SubscriptionStatus @default(TRIALING)\n  currentPeriodStart   DateTime?          @map(\"current_period_start\")\n  currentPeriodEnd     DateTime?          @map(\"current_period_end\")\n  trialEndsAt          DateTime?          @map(\"trial_ends_at\")\n  cancelledAt          DateTime?          @map(\"cancelled_at\")\n  createdAt            DateTime           @default(now()) @map(\"created_at\")\n  updatedAt            DateTime           @updatedAt @map(\"updated_at\")\n\n  @@map(\"subscriptions\")\n}\n\nenum SubscriptionStatus {\n  TRIALING\n  ACTIVE\n  PAST_DUE\n  CANCELLED\n  UNPAID\n}\n\n// ─── Usage Tracking ───\nmodel UsageRecord {\n  id          String   @id @default(dbgenerated(\"gen_random_uuid()\")) @db.Uuid\n  tenantId    String   @map(\"tenant_id\") @db.Uuid\n  metric      String // ai_messages, contacts, storage_mb\n  count       Int\n  periodStart DateTime @map(\"period_start\")\n  periodEnd   DateTime @map(\"period_end\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n\n  @@index([tenantId, metric, periodStart])\n  @@map(\"usage_records\")\n}\n",
